// 毎月 monthlyNewUsers 人を獲得し、churnRate% が離脱する
function simulateMAU(initialMAU, monthlyNewUsers, churnRate, months) {
  const results = [];
  let currentMAU = initialMAU;

  for (let month = 1; month <= months; month++) {
    // 離脱ユーザー数を計算
    const churned = 0; // currentMAU * (churnRate / 100) で計算してください
    // 新しいMAUを計算
    const newMAU = 0; // currentMAU - churned + monthlyNewUsers で計算してください

    results.push({
      month: month,
      mau: Math.round(newMAU),
