function calcChurnRate(startMAU, endMAU, newUsers) {
  return (startMAU - (endMAU - newUsers)) / startMAU * 100;
}

function simulateMAU(initialMAU, monthlyNewUsers, churnRate, months) {
  const results = [];
  let currentMAU = initialMAU;

  for (let month = 1; month <= months; month++) {
    const churned = currentMAU * (churnRate / 100);
    const newMAU = currentMAU - churned + monthlyNewUsers;

    results.push({
      month: month,
      mau: Math.round(newMAU),
      churned: Math.round(churned)
    });

    currentMAU = newMAU;
  }

  return results;
}

const churnRate = calcChurnRate(100000, 98500, 2000);
console.log('月次チャーンレート:', churnRate.toFixed(2) + '%');

console.log('\n-- MAUシミュレーション（チャーン5%）--');
const simulation = simulateMAU(100000, 3000, 5, 3);
simulation.forEach(r => {
  console.log(`${r.month}ヶ月後: MAU ${r.mau.toLocaleString()}人（離脱 ${r.churned.toLocaleString()}人）`);
});
